module top_module(clk, hardreset, reset);input clk, hardreset; 
 output reset; 
 reg [3:0] clear_reg, next_reset_reg; 
 assign reset = clear_reg[3]; 
 initial clear_reg = 4'hF; 
 always @ (posedge clk or posedge hardreset) 
 begin 
  if (hardreset) 
  clear_reg = 4'hF; 
  else clear_reg = next_reset_reg; 
 end 
 always @* 
 begin 
  next_reset_reg = {clear_reg,1'b0}; 
 end 
 endmodule
